mapper.update:
UPDATE agent_run_step
SET request_snapshot_id = #{requestSnapshotId}
WHERE run_id = #{runId}
  AND step_index = #{stepIndex}

UPDATE agent_run_step
SET status = #{status},
    provider = COALESCE(#{provider}, provider),
    model = COALESCE(#{model}, model),
    finish_reason = #{finishReason},
    usage = #{usage,jdbcType=OTHER,typeHandler=org.congcong.algomentor.agent.persistence.postgres.json.JsonbTypeHandler},
    ended_at = #{endedAt}
WHERE run_id = #{runId}
  AND step_index = #{stepIndex}

UPDATE agent_run_step
SET status = #{status},
    error = #{error,jdbcType=OTHER,typeHandler=org.congcong.algomentor.agent.persistence.postgres.json.JsonbTypeHandler},
    ended_at = #{endedAt}
WHERE run_id = #{runId}
  AND step_index = #{stepIndex}

UPDATE agent_tool_call
SET status = #{status},
    result_json = #{resultJson,jdbcType=OTHER,typeHandler=org.congcong.algomentor.agent.persistence.postgres.json.JsonbTypeHandler},
    duration_millis = #{durationMillis},
    result_char_count = #{resultCharCount},
    result_token_estimate = #{resultTokenEstimate},
    ended_at = #{endedAt}
WHERE run_id = #{runId}
  AND step_index = #{stepIndex}
  AND tool_call_id = #{toolCallId}

UPDATE agent_tool_call
SET status = #{status},
    error = #{error,jdbcType=OTHER,typeHandler=org.congcong.algomentor.agent.persistence.postgres.json.JsonbTypeHandler},
    duration_millis = #{durationMillis},
    ended_at = #{endedAt}
WHERE run_id = #{runId}
  AND step_index = #{stepIndex}
  AND tool_call_id = #{toolCallId}
